import org.eclipse.rdf4j.query.algebra.Union;
import org.eclipse.rdf4j.query.algebra.Var;
import org.junit.jupiter.api.Test;

public class ScopeSafeRewritePassTest {

	@Test
	public void appliesFilterAndProjectionRulesThroughOneSession() throws Exception {
		Filter filter = new Filter(
				new Join(pattern("shared", "leftOnly"), pattern("shared", "rightOnly")),
				Var.of("leftOnly"));
		QueryRoot filterRoot = new QueryRoot(filter);
		try (OptimizationSession session = session(filterRoot)) {
			assertThat(apply("filters", filterRoot, session)).isEqualTo(1);
			assertThat(((Join) filterRoot.getArg()).getLeftArg()).isInstanceOf(Filter.class);
			assertThat(session.hasAnalysis()).isTrue();
		}

		Projection projection = new Projection(pattern("x", "y"),
				new ProjectionElemList(new ProjectionElem("x"), new ProjectionElem("y")), false);
		QueryRoot projectionRoot = new QueryRoot(projection);
		try (OptimizationSession session = session(projectionRoot)) {
			assertThat(apply("projections", projectionRoot, session)).isEqualTo(1);
			assertThat(projectionRoot.getArg()).isInstanceOf(StatementPattern.class);
			assertThat(session.hasAnalysis()).isTrue();
		}
	}

	@Test
	public void appliesTheCataloguedAlgebraDistributionRulesToConvergence() throws Exception {
		Extension extension = new Extension(
				new Union(pattern("shared", "a"), pattern("shared", "b")),
				new ExtensionElem(Var.of("shared"), "z"));
		QueryRoot root = new QueryRoot(extension);
		try (OptimizationSession session = session(root)) {
			assertThat(apply("algebra", root, session)).isEqualTo(1);
			assertThat(root.getArg()).isInstanceOf(Union.class);
			assertThat(((Union) root.getArg()).getLeftArg()).isInstanceOf(Extension.class);
			assertThat(session.hasAnalysis()).isTrue();
		}
	}

	private static int apply(String methodName, QueryRoot root, OptimizationSession session) throws Exception {
		Class<?> type = Class.forName(
				"org.eclipse.rdf4j.query.algebra.evaluation.optimizer.scope.ScopeSafeRewritePass");
		Method method = type.getDeclaredMethod(methodName, QueryRoot.class, OptimizationSession.class);
		method.setAccessible(true);
		return (int) method.invoke(null, root, session);
	}

	private static OptimizationSession session(QueryRoot root) {
		return OptimizationSession.open(root, null, null,
				new ScopeSafetyConfiguration(ScopeSafetyMode.ENFORCE, 8, 0, false, 0.0, 10_000, false));
	}

	private static StatementPattern pattern(String first, String second) {
		return new StatementPattern(Var.of(first),
				Var.of("_p", SimpleValueFactory.getInstance().createIRI("urn:p")), Var.of(second));
	}
}
